// Built-in type declarations for the playground.
// Console is inlined (small). Language-extensions and lua-types are loaded from
// pre-bundled .d.ts files (generated by scripts/bundle-types.js).

export const CONSOLE_DTS = `declare var console: Console;
interface Console {
    assert(condition?: boolean, ...data: any[]): void;
    debug(...data: any[]): void;
    error(...data: any[]): void;
    info(...data: any[]): void;
    log(...data: any[]): void;
    trace(...data: any[]): void;
    warn(...data: any[]): void;
}
`;

import langExtDts from "../../assets/types/language-extensions.d.ts?raw";
export { langExtDts };

// Lua target -> bundled lua-types .d.ts content
const luaTypesCache = new Map<string, string>();
const LUA_TYPES_FILES: Record<string, () => Promise<{ default: string }>> = {
  JIT: () => import("../../assets/types/lua-types-jit.d.ts?raw"),
  "5.0": () => import("../../assets/types/lua-types-5.0.d.ts?raw"),
  "5.1": () => import("../../assets/types/lua-types-5.1.d.ts?raw"),
  "5.2": () => import("../../assets/types/lua-types-5.2.d.ts?raw"),
  "5.3": () => import("../../assets/types/lua-types-5.3.d.ts?raw"),
  "5.4": () => import("../../assets/types/lua-types-5.4.d.ts?raw"),
  "5.5": () => import("../../assets/types/lua-types-5.5.d.ts?raw"),
  universal: () => import("../../assets/types/lua-types-5.1.d.ts?raw"),
};

export async function getLuaTypesDts(luaTarget: string): Promise<string> {
  const target = luaTarget || "JIT";
  const cached = luaTypesCache.get(target);
  if (cached) return cached;
  const loader = LUA_TYPES_FILES[target] ?? LUA_TYPES_FILES["JIT"];
  const mod = await loader();
  luaTypesCache.set(target, mod.default);
  return mod.default;
}

// All available built-in type names for the sidebar UI
export const AVAILABLE_TYPES: readonly { name: string; url?: string }[] = [
  { name: "console" },
  {
    name: "language-extensions",
    url: "https://typescripttolua.github.io/docs/advanced/language-extensions",
  },
  { name: "lua-types", url: "https://github.com/TypeScriptToLua/lua-types" },
] as const;
